const texts = $json.competitor_text;
const urls = $json.url;
let combined = '';
for (let i = 0; i < texts.length; i++) {
  const text = texts[i] || '';
  combined += `\n\n--- КОНКУРЕНТ ${i+1}: ${urls[i]} ---\n${text.substring(0, 12000)}`;
}

return [{
  json: {
    combined_text: combined,
    h1: $json.h1,
    keywords: $json.keywords,
    neuroanalysis: $json.neuroanalysis,
    page_type: $json.page_type,
    volume: $json.volume || '',
    faq: $json.faq || ''
  }
}];

const row = $json;
const stopDomains = ['zoon.ru', 'docdoc.ru', '2gis.ru', 'youtube.com'];

const rawUrls = (row['Конкуренты ТОП-10'] || '').split(/\r?\n/).map(u => u.trim()).filter(Boolean);
const urls = rawUrls.filter(url => !stopDomains.some(domain => url.includes(domain)));

if (urls.length === 0) throw new Error('Нет URL после фильтрации');

return urls.map(url => ({
  json: {
    url,
    row_num: row['№'],
    h1: row['H1 (главный ключ)'],
    keywords: row['Ключевые'],
    neuroanalysis: row['Нейроанализ'],
    page_type: row['Тип']
  }
}));

let rawText = '';
if ($json.data) {
  rawText = $json.data;
} else if ($json.body) {
  rawText = $json.body;
} else if ($json.html) {
  rawText = $json.html;
} else if ($json['0'] !== undefined) {
  rawText = Object.values($json).join('');
}

let text = rawText.includes('<') && rawText.includes('>')
  ? rawText.replace(/<[^>]+>/g, ' ')
  : rawText;

text = text.replace(/\[([^\]]+)\]\([^)]+\)/g, '$1');

const cutPatterns = [
  /\n#+\s*(Отзывы|Комментарии|Comments|Reviews|Похожие|Рекомендуем|Читайте также|Смотрите также|Популярное|Теги)/i,
  /\d+\s*отзыв/i,
  /Оставить отзыв/i,
  /Войдите чтобы оставить/i
];

for (const pattern of cutPatterns) {
  const match = text.search(pattern);
  if (match > 500) {
    text = text.substring(0, match);
    break;
  }
}

text = text.replace(/\s+/g, ' ').trim();

const source = $json;
const urlItems = $('Разбиваем URL конкурентов1').all();
const urlData = urlItems[$itemIndex]?.json || {};

console.log('URL:', $json.url, '| rawText len:', rawText.length, '| final len:', text.length);

return {
  json: {
    competitor_text: text,
    url: source.url || '',
    row_num: source.row_num,
    h1: urlData.h1 || '',
    keywords: urlData.keywords || '',
    neuroanalysis: urlData.neuroanalysis || '',
    page_type: urlData.page_type || ''
  }
};

let html = '';
if ($json.body) {
  html = $json.body;
} else if ($json.data) {
  html = $json.data;
} else if ($json['0'] !== undefined) {
  html = Object.values($json).join('');
}
return { json: { html: html } };

const source = $('Разбиваем URL конкурентов1').item.json;
return {
  json: {
    html: $json.data || $json.body || $json.html || '',
    url: source.url,
    row_num: source.row_num,
    h1: source.h1,
    keywords: source.keywords,
    neuroanalysis: source.neuroanalysis,
    page_type: source.page_type
  }
};

let analysisData = {};
try {
  let raw = $json.text || '';
  raw = raw.replace(/^```json\s*/i, '').replace(/```\s*$/i, '').trim();
  analysisData = JSON.parse(raw);
} catch(e) {}

const src = $('Собираем блок конкурентов').item.json;
const neuroanalysis = src.neuroanalysis || '';

const recBlock = neuroanalysis.match(/Рекомендации по расширению[:\s]*\n([\s\S]*?)(?:\n\n|Источники|$)/i);
const lsiFromNeuro = recBlock
  ? recBlock[1].split('\n').map(s => s.trim()).filter(s => s.length > 3)
  : [];

const lsiFromCompetitors = (analysisData.top_phrases || []).map(p =>
  typeof p === 'object' ? p.phrase : p
).filter(Boolean);

const allLsi = [...new Set([...lsiFromNeuro, ...lsiFromCompetitors])];
const top15 = allLsi.slice(0, 15);

return [{
  json: {
    ...analysisData,
    lsi_merged: top15,
    lsi_from_neuro: lsiFromNeuro,
    lsi_from_competitors: lsiFromCompetitors,
    h1: src.h1,
    keywords: src.keywords,
    neuroanalysis: neuroanalysis,
    page_type: src.page_type,
    volume: src.volume || '',
    faq: src.faq || ''
  }
}];

const data = $json;
const documentId = $json.documentId;

const norm = s => (s || '').replace(/\r\n/g, '\n').replace(/\r/g, '\n');
data.neuroanalysis = norm(data.neuroanalysis);
data.h1 = norm(data.h1);
data.page_type = norm(data.page_type);
data.tone = norm(data.tone);
data.keywords = norm(data.keywords);
if (data.lsi_merged) data.lsi_merged = data.lsi_merged.map(norm);

const insertRequests = [];
const styleRequests = [];
let idx = 1;

function ins(text) {
  const start = idx;
  insertRequests.push({ insertText: { location: { index: idx }, text } });
  idx += text.length;
  return start;
}

function schedBold(start, end) {
  styleRequests.push({
    updateTextStyle: {
      range: { startIndex: start, endIndex: end },
      textStyle: { bold: true },
      fields: 'bold'
    }
  });
}

function schedHeading(level, start, end) {
  styleRequests.push({
    updateParagraphStyle: {
      range: { startIndex: start, endIndex: end },
      paragraphStyle: { namedStyleType: level },
      fields: 'namedStyleType'
    }
  });
}

let s = ins(`Техническое задание к копирайту для темы "${data.h1}"\n`);
schedHeading('HEADING_2', s, idx);
ins('\n');

s = ins('Общая информация\n');
schedHeading('HEADING_3', s, idx);
schedBold(s, idx - 1);
ins(`Тип страницы: ${data.page_type}\n`);
ins(`Рекомендуемый объём: ~${data.avg_volume} символов без пробелов\n`);
ins(`Тональность: ${data.tone}\n`);
ins(`H1: ${data.h1}\n`);
ins('\n');

s = ins('LSI-фразы\n');
schedHeading('HEADING_3', s, idx);
schedBold(s, idx - 1);
ins('LSI-фразы важно употребить в тексте минимум 1-м вхождением с учётом словоформы и морфологии.\n');
const lsiClean = (data.lsi_merged || []).filter(p => !/рекомендации по расширению/i.test(p));
ins(lsiClean.join('; ') + '\n');
ins('\n');

s = ins('Топ-фразы конкурентов\n');
schedHeading('HEADING_3', s, idx);
schedBold(s, idx - 1);
(data.top_phrases || []).forEach(p => {
  const bc = p.by_competitor || {};
  ins(`${p.phrase}: ${bc['1']||0} / ${bc['2']||0} / ${bc['3']||0} / ${bc['4']||0} -- ${p.avg}\n`);
});
ins('\n');

s = ins('Структура страницы\n');
schedHeading('HEADING_3', s, idx);
schedBold(s, idx - 1);
(data.structure || []).forEach(section => {
  s = ins(`${section.heading}\n`);
  schedBold(s, idx - 1);
  (section.theses || []).forEach(thesis => {
    ins(`• ${thesis}\n`);
  });
  ins('\n');
});

s = ins('Обязательные блоки контента\n');
schedHeading('HEADING_3', s, idx);
schedBold(s, idx - 1);
(data.common_blocks || []).forEach((block, i) => {
  ins(`${i+1}. ${block}\n`);
});
ins('\n');

s = ins('Чего нет у конкурентов\n');
schedHeading('HEADING_3', s, idx);
schedBold(s, idx - 1);
(data.content_gaps || []).forEach((gap, i) => {
  ins(`${i+1}. ${gap}\n`);
});
ins('\n');

s = ins('Нейроанализ\n');
schedHeading('HEADING_3', s, idx);
schedBold(s, idx - 1);
const neuro = data.neuroanalysis || '';
const parts = neuro.split(/(Шаг \d+:[^\n]*|Источники анализа:)/);
parts.forEach(part => {
  if (!part) return;
  if (/^Шаг \d+:/.test(part.trim()) || /^Источники анализа:/.test(part.trim())) {
    ins('\n');
    s = ins(part.trim() + '\n');
    schedBold(s, idx - 1);
  } else {
    ins(part);
  }
});

const requests = [...insertRequests, ...styleRequests];
return [{ json: { documentId, requestsJson: JSON.stringify({ requests }) } }];

const items = $input.all();
const lastRowNum = items[items.length - 1].json.row_num;
const filtered = items.filter(i => i.json.row_num === lastRowNum);
const withText = filtered.filter(i => 
  i.json.competitor_text && 
  typeof i.json.competitor_text === 'string' &&
  i.json.competitor_text.length > 50
);
const result = withText.length > 0 ? withText : filtered;
if (result.length === 0) throw new Error('Нет items для row_num: ' + lastRowNum);
const first = result[0].json;
return [{ json: { 
  competitor_text: result.map(i => i.json.competitor_text || ''),
  url: result.map(i => i.json.url || ''),
  h1: first.h1,
  keywords: first.keywords,
  neuroanalysis: first.neuroanalysis,
  page_type: first.page_type,
  row_num: first.row_num
} }];
